// ===== EDIT YOUR PLAN HERE =====
// dryRun:true  -> selects vouchers but does NOT pay (safe test).
// dryRun:false -> real purchases (charges your card, hits the milestone).
const dryRun = true;

const plan = {
  brands: {
    amazonpay: 'gko2OEEac6Y24dmH/bBa7g=='
    // add more brands: open the product on shopwise, copy productId from /giftcard?productId=...
  },
  cards: {
    charge: 0, // PayU saved-card slot 0 = Gold Charge
    mrcc: 1    // PayU saved-card slot 1 = MRCC
  },
  jobs: [
    // count = number of separate transactions (each counts toward a milestone)
    { name: 'MRCC Rs.1500 Amazon Pay', card: 'mrcc', brand: 'amazonpay', denominations: [{ amount: 1000, qty: 1 }, { amount: 500, qty: 1 }], count: 1 }
    // , { name: 'Charge Rs.1000 Amazon Pay', card: 'charge', brand: 'amazonpay', denominations: [{ amount: 1000, qty: 1 }], count: 6 }
  ]
};

return [{ json: { dryRun, plan } }];

const r = $input.first().json || {};
const results = Array.isArray(r.results) ? r.results : [];
const ok = results.filter(x => x && x.ok).length;
const vouchers = [];
for (const x of results) if (x && x.voucher && Array.isArray(x.voucher.vouchers)) vouchers.push(...x.voucher.vouchers);
return [{ json: {
  summary: `${ok}/${results.length} job(s) OK${results[0] && results[0].dryRun ? ' (dry-run, no charge)' : ''}`,
  ok_jobs: ok,
  total_jobs: results.length,
  vouchers,
  raw: r
} }];
